module RefModule (
    input [1:0] in,
    output [3:0] out
);

    // 2-bit binary decoder logic
    wire __in_tmp = (in == 2'b00);
    assign out = __in_tmp ? 4'b0001 : (in == 2'b01) ? 4'b0010 :
                 (in == 2'b10) ? 4'b0100 :
                                 4'b1000;

endmodule
